import{c as i,Q as l,j as r,g as e,n as t}from"./chunks/framework.hhGiamYR.js";const h=JSON.parse('{"title":"论小洛伦佐去世后佛罗伦","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/209-论小洛伦佐去世后佛罗伦.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/209-论小洛伦佐去世后佛罗伦.md"}'),o={name:"research/machiavelli/machiavelli/diplomatic/lower/209-论小洛伦佐去世后佛罗伦.md"};function c(n,a,s,m,_,d){return l(),r("div",null,[...a[0]||(a[0]=[e("h1",{id:"论小洛伦佐去世后佛罗伦",tabindex:"-1"},[t("论小洛伦佐去世后佛罗伦 "),e("a",{class:"header-anchor",href:"#论小洛伦佐去世后佛罗伦","aria-label":'Permalink to "论小洛伦佐去世后佛罗伦"'},"​")],-1),e("p",null,"论小洛伦佐去世后佛罗伦萨的政务 至于那些偏好一个比科西莫政府更具包容性之政府的人，我要说，除 非在一种能够使其成为秩序良好之共和国意义上它是包容的，否则，这种 包容性只会使之毁灭得更快。如果他们能够详尽地说明他们将如何来组建 它，那么我会详尽地回应。但由于他们只是泛泛而谈，那我也只能泛泛地 回应，我相信以下的回复就足够了。在拒斥科西莫式的政府时，我说过， 除非它成为一个真正的君主国或共和国，否则它就不会是一个稳定的政 府；因为，所有介于两者之间的政府均有其缺陷。原因是一目了然的，因 为，君主国仅有一条解体的道路，即降格为共和国；同样，共和国也仅有 一条瓦解的道路，即擢升为君主国。中间类型的政府有两条路可走：既可 以擢升为君主国，也可以降格为共和国；所以，它们就不可能稳固。 因此，陛下如果为了您自身的荣耀和您朋友的安全给予佛罗伦萨一个 稳定的政府，那么,除了建立一个机制完备的、真正的君主国或共和国之 外，别无他途。其他任何形式的政府都徒劳无益，朝不保夕。对于君主 国，我不拟详细探讨，既因为要在此地建立君主国困难重重，也因为缺乏 便利①。而且，陛下应该懂得，在所有公民习惯了平等的城邦里，建立一 个君主国是何等艰难；而在那些公民习惯了不平等的城邦里，建立一个共 和国也是何等艰难。为了在公民之间存在严重不平等的米兰创建一个共和 国，所有的贵族都必须被拔除，使之与他人实现平等；因为，他们当中有 些人凌驾于一切规则之上，以致法律都不足以制服他们，必须通过一个强 有力的声音与国王般的权力才能制服他们。相反，为了在公民之间存在严 格平等的佛罗伦萨创建一个君主国，则必须确立不平等；设立拥有城堡与 庄园贵族领主，他们会拿起武器、率领扈从支持君主镇压城邦以及整个地 区。没有贵族，君主无法独自担当君主国的重任；因为，在他与普通民众 之间，必须有一个能够助其一臂之力的中间阶级。所有存在君主的国家都 见证了这一点，特别是在法兰西王国，绅士( gentiluomini) 统治人民，",-1),e("p",null,"①指在小洛伦佐去世后，梅迪奇家族缺乏直接继承人。 ——中译者注",-1),e("p",null,"Legazioni,commissarie,scrittidi governo",-1)])])}const f=i(o,[["render",c]]);export{h as __pageData,f as default};
